// Grafana unified alerting webhook payload (v10+ format)
const body = $input.first().json.body || $input.first().json || {};

const status  = body.status || 'firing';   // 'firing' | 'resolved'
const alerts  = body.alerts || [];

const isFiring   = status === 'firing';
const statusEmoji = isFiring ? '🔴' : '✅';
const statusLabel = isFiring ? 'FIRING' : 'RESOLVED';

// ── Parse first alert (GPU alerts are typically one at a time) ───────────────
const alert = alerts[0] || {};
const labels      = alert.labels || {};
const annotations = alert.annotations || {};

const alertName   = labels.alertname   || 'GPU Alert';
const instance    = labels.instance    || 'host';
const summary     = annotations.summary     || alertName;
const description = annotations.description || '';

// ── Try to extract current GPU value from annotations (if Grafana passes it) ─
const valueStr = annotations.value || labels.value || '';
const valueLine = valueStr ? `\n*Current value:* ${valueStr}` : '';

// ── Time ────────────────────────────────────────────────────────────────────
const firedAt = alert.startsAt ? new Date(alert.startsAt).toLocaleString('en-US', { timeZone: 'America/New_York' }) : new Date().toLocaleString();

// ── Grafana deep-link ────────────────────────────────────────────────────────
const grafanaUrl  = alert.generatorURL || 'http://localhost:3001';
const dashboardUrl = 'http://localhost:3001/d/biulatech-ai-hub';

const blocks = [
  {
    type: 'header',
    text: {
      type: 'plain_text',
      text: `${statusEmoji} GPU Alert ${statusLabel}: ${alertName}`,
      emoji: true
    }
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text:
        `*${summary}*${valueLine}\n` +
        (description ? `${description}\n` : '') +
        `*Instance:* ${instance}  |  *Fired at:* ${firedAt}`
    }
  },
  {
    type: 'actions',
    elements: [
      {
        type: 'button',
        text: { type: 'plain_text', text: '📊 Open Grafana', emoji: true },
        url: dashboardUrl,
        style: isFiring ? 'danger' : 'primary'
      },
      {
        type: 'button',
        text: { type: 'plain_text', text: '🔗 Alert Rule', emoji: true },
        url: grafanaUrl
      }
    ]
  }
];

return [{ json: {
  status,
  isFiring,
  alertName,
  blocks,
  payload: JSON.stringify({
    channel: 'C0AL38DHHGC',   // #ops-alerts
    blocks,
    text: `${statusEmoji} GPU Alert ${statusLabel}: ${summary}`  // fallback text
  })
}}];
